const designImportMigration=require("../../../../../../design_import_migration");const _kgb_=designImportMigration.getMxgoUtils().getKgbGlobal();class ActionBarBtnJavascriptSnippet{getId(t){let e=[];e.push(t);e.push(_kgb_.modules.utils.getKUID().toString());return e.join("_")}constructor(){this.setDefault()}setDefault(){this.addSnippetAction={id:this.getId("ADD_SNIPPET"),codeSnippet:"alert('test')",type:"ADD_SNIPPET"}}setAddSnippetCode(t){if(t?.code?.javascript){this.addSnippetAction.codeSnippet="try {\n"+t?.code?.javascript+"\n} catch(e) { \n console.log(e); alert(e); \n}"}else{this.addSnippetAction.codeSnippet="// Please contact your administrator to support this"}}toActions(){return[this.addSnippetAction]}}module.exports={ActionBarBtnJavascriptSnippet:ActionBarBtnJavascriptSnippet};